import{_ as e,c as o,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"多渠道与平台 | Clawdbot 教程","description":"学习如何配置和使用 Clawdbot 的多渠道系统，包括 WhatsApp、Telegram、Slack、Discord、Google Chat、Signal、iMessage、LINE、WebChat、macOS、iOS 和 Android 平台。","frontmatter":{"title":"多渠道与平台 | Clawdbot 教程","sidebarTitle":"接入常用聊天工具","subtitle":"多渠道与平台","description":"学习如何配置和使用 Clawdbot 的多渠道系统，包括 WhatsApp、Telegram、Slack、Discord、Google Chat、Signal、iMessage、LINE、WebChat、macOS、iOS 和 Android 平台。","tags":["channels","platforms","integration"],"order":60},"headers":[],"relativePath":"zh/moltbot/moltbot/platforms/index.md","filePath":"zh/moltbot/moltbot/platforms/index.md"}'),r={name:"zh/moltbot/moltbot/platforms/index.md"};function i(s,a,n,h,d,g){return l(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="多渠道与平台" tabindex="-1">多渠道与平台 <a class="header-anchor" href="#多渠道与平台" aria-label="Permalink to &quot;多渠道与平台&quot;">​</a></h1><p>Clawdbot 通过统一的 Gateway 控制平面，支持多种通信渠道和平台，让你在熟悉的界面上与 AI 助手交互。</p><h2 id="章节概述" tabindex="-1">章节概述 <a class="header-anchor" href="#章节概述" aria-label="Permalink to &quot;章节概述&quot;">​</a></h2><p>本章节介绍 Clawdbot 支持的所有通信渠道和平台，包括即时通讯应用（WhatsApp、Telegram、Slack、Discord 等）、移动端节点（iOS、Android）和桌面应用（macOS）。学习如何配置这些渠道，让 AI 助手无缝融入你的日常工作流。</p><h2 id="子页面导航" tabindex="-1">子页面导航 <a class="header-anchor" href="#子页面导航" aria-label="Permalink to &quot;子页面导航&quot;">​</a></h2><h3 id="渠道概览" tabindex="-1">渠道概览 <a class="header-anchor" href="#渠道概览" aria-label="Permalink to &quot;渠道概览&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">多渠道系统概览</a></strong> - 了解 Clawdbot 支持的所有通信渠道及其特点，掌握渠道配置的基本概念。</li></ul><h3 id="即时通讯渠道" tabindex="-1">即时通讯渠道 <a class="header-anchor" href="#即时通讯渠道" aria-label="Permalink to &quot;即时通讯渠道&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - 配置和使用 WhatsApp 渠道（基于 Baileys），支持设备链接和群组管理。</li><li><strong><a href="./telegram/">Telegram</a></strong> - 配置和使用 Telegram 渠道（基于 grammY Bot API），设置 Bot Token 和 Webhook。</li><li><strong><a href="./slack/">Slack</a></strong> - 配置和使用 Slack 渠道（基于 Bolt），集成到你的工作空间。</li><li><strong><a href="./discord/">Discord</a></strong> - 配置和使用 Discord 渠道（基于 discord.js），支持服务器和频道。</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - 配置和使用 Google Chat 渠道，与 Google Workspace 集成。</li><li><strong><a href="./signal/">Signal</a></strong> - 配置和使用 Signal 渠道（基于 signal-cli），保护隐私的通信。</li><li><strong><a href="./imessage/">iMessage</a></strong> - 配置和使用 iMessage 渠道（macOS 专属），与 macOS 消息应用集成。</li><li><strong><a href="./line/">LINE</a></strong> - 配置和使用 LINE 渠道（Messaging API），与 LINE 用户交互。</li></ul><h3 id="web-与原生应用" tabindex="-1">Web 与原生应用 <a class="header-anchor" href="#web-与原生应用" aria-label="Permalink to &quot;Web 与原生应用&quot;">​</a></h3><ul><li><strong><a href="./webchat/">WebChat 界面</a></strong> - 使用内置的 WebChat 界面与 AI 助手交互，无需配置外部渠道。</li><li><strong><a href="./macos-app/">macOS 应用</a></strong> - 了解 macOS 菜单栏应用的功能，包括 Voice Wake、Talk Mode 和远程控制。</li><li><strong><a href="./ios-node/">iOS 节点</a></strong> - 配置 iOS 节点以执行设备本地操作（Camera、Canvas、Voice Wake）。</li><li><strong><a href="./android-node/">Android 节点</a></strong> - 配置 Android 节点以执行设备本地操作（Camera、Canvas）。</li></ul><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><p>根据你的使用场景，推荐以下学习顺序：</p><h3 id="新手快速上手" tabindex="-1">新手快速上手 <a class="header-anchor" href="#新手快速上手" aria-label="Permalink to &quot;新手快速上手&quot;">​</a></h3><p>如果你是第一次使用 Clawdbot，建议按照以下顺序学习：</p><ol><li><strong><a href="./channels-overview/">多渠道系统概览</a></strong> - 先了解整体架构和渠道概念</li><li><strong><a href="./webchat/">WebChat 界面</a></strong> - 最简单的方式，无需任何配置即可开始使用</li><li><strong>选择一个常用渠道</strong> - 根据你的日常习惯选择： <ul><li>日常聊天 → <a href="./whatsapp/">WhatsApp</a> 或 <a href="./telegram/">Telegram</a></li><li>团队协作 → <a href="./slack/">Slack</a> 或 <a href="./discord/">Discord</a></li><li>macOS 用户 → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="移动端集成" tabindex="-1">移动端集成 <a class="header-anchor" href="#移动端集成" aria-label="Permalink to &quot;移动端集成&quot;">​</a></h3><p>如果你想在手机上使用 Clawdbot：</p><ol><li><strong><a href="./ios-node/">iOS 节点</a></strong> - 配置 iPhone/iPad 上的本地功能</li><li><strong><a href="./android-node/">Android 节点</a></strong> - 配置 Android 设备上的本地功能</li><li><strong><a href="./macos-app/">macOS 应用</a></strong> - 使用 macOS 应用作为控制中心</li></ol><h3 id="企业级部署" tabindex="-1">企业级部署 <a class="header-anchor" href="#企业级部署" aria-label="Permalink to &quot;企业级部署&quot;">​</a></h3><p>如果你需要在团队环境中部署：</p><ol><li><strong><a href="./slack/">Slack</a></strong> - 与团队工作空间集成</li><li><strong><a href="./discord/">Discord</a></strong> - 建立社区服务器</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - 与 Google Workspace 集成</li></ol><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>在开始学习本章节之前，建议先完成：</p><ul><li><strong><a href="./../start/getting-started/">快速开始</a></strong> - 完成 Clawdbot 的安装和基础配置</li><li><strong><a href="./../start/onboarding-wizard/">向导式配置</a></strong> - 通过向导完成 Gateway 和渠道的基本设置</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果你已经完成了向导式配置，一些渠道可能已经自动配置好了。可以跳过重复的配置步骤，直接查看特定渠道的高级功能。</p></div><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章节的学习后，你可以继续探索：</p><ul><li><strong><a href="./../advanced/models-auth/">AI 模型与认证配置</a></strong> - 配置不同的 AI 模型提供商</li><li><strong><a href="./../advanced/session-management/">会话管理与多 Agent</a></strong> - 学习会话隔离和子 Agent 协作</li><li><strong><a href="./../advanced/tools-browser/">工具系统</a></strong> - 使用浏览器自动化、命令执行等工具</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><details class="details custom-block"><summary>我可以同时使用多个渠道吗？</summary><p>是的！Clawdbot 支持同时启用多个渠道。你可以在不同渠道上接收和发送消息，所有消息都通过统一的 Gateway 处理。</p></details><details class="details custom-block"><summary>哪个渠道最推荐？</summary><p>这取决于你的使用场景：</p><ul><li><strong>WebChat</strong> - 最简单，无需任何配置</li><li><strong>WhatsApp</strong> - 适合与朋友和家人聊天</li><li><strong>Telegram</strong> - Bot API 稳定，适合自动回复</li><li><strong>Slack/Discord</strong> - 适合团队协作</li></ul></details><details class="details custom-block"><summary>配置渠道需要付费吗？</summary><p>大多数渠道本身是免费的，但部分渠道可能有成本：</p><ul><li>WhatsApp Business API - 可能产生费用</li><li>Google Chat - 需要 Google Workspace 账户</li><li>其他渠道 - 通常免费，只需申请 Bot Token</li></ul></details>',33)])])}const p=e(r,[["render",i]]);export{m as __pageData,p as default};
